<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Personal Expense Tracker</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            background-color: #f5f5f5;
            padding: 20px;
        }

        .container {
            max-width: 1000px;
            margin: 0 auto;
            background-color: white;
            border-radius: 8px;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
            padding: 30px;
        }

        h1 {
            margin-bottom: 30px;
            color: #333;
        }

        .form-section {
            margin-bottom: 30px;
            padding: 20px;
            background-color: #f9f9f9;
            border-radius: 6px;
            border: 1px solid #e0e0e0;
        }

        .form-section h2 {
            font-size: 16px;
            margin-bottom: 15px;
            color: #555;
        }

        .form-group {
            margin-bottom: 15px;
        }

        label {
            display: block;
            margin-bottom: 5px;
            font-weight: 500;
            color: #555;
        }

        input, select {
            width: 100%;
            padding: 8px 12px;
            border: 1px solid #ddd;
            border-radius: 4px;
            font-size: 14px;
            font-family: inherit;
        }

        input:focus, select:focus {
            outline: none;
            border-color: #4CAF50;
            box-shadow: 0 0 0 2px rgba(76, 175, 80, 0.2);
        }

        .form-row {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 15px;
        }

        @media (max-width: 600px) {
            .form-row {
                grid-template-columns: 1fr;
            }
        }

        #form-error {
            color: #d32f2f;
            font-size: 14px;
            margin-bottom: 15px;
            min-height: 20px;
        }

        button {
            background-color: #4CAF50;
            color: white;
            padding: 10px 20px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-size: 14px;
            font-weight: 600;
            transition: background-color 0.2s;
        }

        button:hover {
            background-color: #45a049;
        }

        button:active {
            background-color: #3d8b40;
        }

        .exp-del {
            background-color: #f44336;
            padding: 6px 12px;
            font-size: 12px;
        }

        .exp-del:hover {
            background-color: #da190b;
        }

        .filters-section {
            margin-bottom: 30px;
            padding: 20px;
            background-color: #f9f9f9;
            border-radius: 6px;
            border: 1px solid #e0e0e0;
        }

        .filters-section h2 {
            font-size: 16px;
            margin-bottom: 15px;
            color: #555;
        }

        .filter-row {
            display: grid;
            grid-template-columns: 1fr 1fr 1fr;
            gap: 15px;
        }

        @media (max-width: 600px) {
            .filter-row {
                grid-template-columns: 1fr;
            }
        }

        .summary-section {
            margin-bottom: 30px;
            padding: 20px;
            background-color: #e8f5e9;
            border-radius: 6px;
            border: 1px solid #4CAF50;
        }

        .total-display {
            font-size: 28px;
            font-weight: bold;
            color: #2e7d32;
            margin-bottom: 20px;
        }

        .category-totals {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
            gap: 10px;
        }

        .cat-total {
            background-color: white;
            padding: 12px;
            border-radius: 4px;
            text-align: center;
            border-left: 4px solid #4CAF50;
        }

        .cat-total-label {
            font-size: 12px;
            color: #999;
            margin-bottom: 4px;
        }

        .cat-total-amount {
            font-size: 16px;
            font-weight: 600;
            color: #2e7d32;
        }

        .expenses-section {
            margin-top: 30px;
        }

        .expenses-section h2 {
            margin-bottom: 15px;
            color: #333;
        }

        .expenses-list {
            display: flex;
            flex-direction: column;
            gap: 10px;
        }

        .expense {
            display: grid;
            grid-template-columns: 100px 120px 100px 1fr 80px;
            gap: 15px;
            padding: 15px;
            background-color: #f9f9f9;
            border: 1px solid #e0e0e0;
            border-radius: 4px;
            align-items: center;
        }

        @media (max-width: 600px) {
            .expense {
                grid-template-columns: 1fr;
            }
        }

        .expense-amount {
            font-weight: 600;
            color: #2e7d32;
            font-size: 16px;
        }

        .expense-category {
            color: #666;
            font-size: 14px;
        }

        .expense-date {
            color: #999;
            font-size: 14px;
        }

        .expense-note {
            color: #666;
            font-size: 13px;
            word-break: break-word;
        }

        .empty-state {
            text-align: center;
            padding: 40px 20px;
            color: #999;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Personal Expense Tracker</h1>

        <div class="form-section">
            <h2>Add Expense</h2>
            <div id="form-error"></div>
            <div class="form-row">
                <div class="form-group">
                    <label for="amount">Amount</label>
                    <input type="number" id="amount" step="0.01" placeholder="0.00">
                </div>
                <div class="form-group">
                    <label for="category">Category</label>
                    <select id="category">
                        <option value="">Select a category</option>
                        <option value="groceries">Groceries</option>
                        <option value="transport">Transport</option>
                        <option value="bills">Bills</option>
                        <option value="fun">Fun</option>
                    </select>
                </div>
            </div>
            <div class="form-row">
                <div class="form-group">
                    <label for="date">Date</label>
                    <input type="date" id="date">
                </div>
                <div class="form-group">
                    <label for="note">Note (optional)</label>
                    <input type="text" id="note" placeholder="Add a note...">
                </div>
            </div>
            <button type="button" id="add-expense">Add Expense</button>
        </div>

        <div class="filters-section">
            <h2>Filters</h2>
            <div class="filter-row">
                <div class="form-group">
                    <label for="filter-category">Category</label>
                    <select id="filter-category">
                        <option value="">All Categories</option>
                        <option value="groceries">Groceries</option>
                        <option value="transport">Transport</option>
                        <option value="bills">Bills</option>
                        <option value="fun">Fun</option>
                    </select>
                </div>
                <div class="form-group">
                    <label for="filter-from">From Date</label>
                    <input type="date" id="filter-from">
                </div>
                <div class="form-group">
                    <label for="filter-to">To Date</label>
                    <input type="date" id="filter-to">
                </div>
            </div>
        </div>

        <div class="summary-section">
            <div class="total-display">Total: $<span id="total">0.00</span></div>
            <div class="category-totals" id="category-totals">
                <div class="cat-total" data-cat="groceries">
                    <div class="cat-total-label">Groceries</div>
                    <div class="cat-total-amount">$0.00</div>
                </div>
                <div class="cat-total" data-cat="transport">
                    <div class="cat-total-label">Transport</div>
                    <div class="cat-total-amount">$0.00</div>
                </div>
                <div class="cat-total" data-cat="bills">
                    <div class="cat-total-label">Bills</div>
                    <div class="cat-total-amount">$0.00</div>
                </div>
                <div class="cat-total" data-cat="fun">
                    <div class="cat-total-label">Fun</div>
                    <div class="cat-total-amount">$0.00</div>
                </div>
            </div>
        </div>

        <div class="expenses-section">
            <h2>Expenses</h2>
            <div class="expenses-list" id="expenses-list">
                <div class="empty-state">No expenses yet. Add one to get started!</div>
            </div>
        </div>
    </div>

    <script>
        const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
        const STORAGE_KEY = 'expenses';
        let expenses = [];

        function loadExpenses() {
            const stored = localStorage.getItem(STORAGE_KEY);
            expenses = stored ? JSON.parse(stored) : [];
        }

        function saveExpenses() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        }

        function validateExpense(amount, date) {
            if (!amount || isNaN(amount) || parseFloat(amount) <= 0) {
                return false;
            }
            if (!date) {
                return false;
            }
            return true;
        }

        function addExpense() {
            const amountInput = document.getElementById('amount');
            const categoryInput = document.getElementById('category');
            const dateInput = document.getElementById('date');
            const noteInput = document.getElementById('note');
            const errorDiv = document.getElementById('form-error');

            const amount = parseFloat(amountInput.value);
            const category = categoryInput.value;
            const date = dateInput.value;
            const note = noteInput.value.trim();

            if (!validateExpense(amount, date)) {
                errorDiv.textContent = 'Please enter a valid amount (greater than 0) and select a date.';
                return;
            }

            if (!category) {
                errorDiv.textContent = 'Please select a category.';
                return;
            }

            errorDiv.textContent = '';

            const expense = {
                id: Date.now(),
                amount: parseFloat(amount.toFixed(2)),
                category: category,
                date: date,
                note: note
            };

            expenses.unshift(expense);
            saveExpenses();
            amountInput.value = '';
            categoryInput.value = '';
            dateInput.value = '';
            noteInput.value = '';

            render();
        }

        function deleteExpense(id) {
            expenses = expenses.filter(e => e.id !== id);
            saveExpenses();
            render();
        }

        function getFilteredExpenses() {
            const categoryFilter = document.getElementById('filter-category').value;
            const fromFilter = document.getElementById('filter-from').value;
            const toFilter = document.getElementById('filter-to').value;

            return expenses.filter(e => {
                if (categoryFilter && e.category !== categoryFilter) {
                    return false;
                }
                if (fromFilter && e.date < fromFilter) {
                    return false;
                }
                if (toFilter && e.date > toFilter) {
                    return false;
                }
                return true;
            });
        }

        function render() {
            const filtered = getFilteredExpenses();
            const expensesList = document.getElementById('expenses-list');

            if (filtered.length === 0) {
                expensesList.innerHTML = '<div class="empty-state">No expenses match the filters.</div>';
            } else {
                expensesList.innerHTML = filtered.map(e => {
                    return `
                        <div class="expense">
                            <div class="expense-amount">$${e.amount.toFixed(2)}</div>
                            <div class="expense-category">${e.category.charAt(0).toUpperCase() + e.category.slice(1)}</div>
                            <div class="expense-date">${e.date}</div>
                            <div class="expense-note">${e.note || '—'}</div>
                            <button type="button" class="exp-del" onclick="deleteExpense(${e.id})">Delete</button>
                        </div>
                    `;
                }).join('');
            }

            updateTotal(filtered);
            updateCategoryTotals(filtered);
        }

        function updateTotal(filtered) {
            const total = filtered.reduce((sum, e) => sum + e.amount, 0);
            document.getElementById('total').textContent = total.toFixed(2);
        }

        function updateCategoryTotals(filtered) {
            const categoryTotals = {};
            CATEGORIES.forEach(cat => {
                categoryTotals[cat] = 0;
            });

            filtered.forEach(e => {
                categoryTotals[e.category] += e.amount;
            });

            CATEGORIES.forEach(cat => {
                const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
                if (el) {
                    const amountEl = el.querySelector('.cat-total-amount');
                    if (amountEl) {
                        amountEl.textContent = `$${categoryTotals[cat].toFixed(2)}`;
                    }
                }
            });
        }

        document.getElementById('add-expense').addEventListener('click', addExpense);
        document.getElementById('filter-category').addEventListener('change', render);
        document.getElementById('filter-from').addEventListener('change', render);
        document.getElementById('filter-to').addEventListener('change', render);

        loadExpenses();
        render();
    </script>
</body>
</html>
